// Import necessary libraries
const Web3 = require('web3');
const ethers = require('ethers');

// Configure wallet with private keys
const privateKey = 'your_private_key';
const wallet = new ethers.Wallet(privateKey);

// Connect to Ethereum blockchain
const provider = new Web3.providers.HttpProvider('your_ethereum_node_url');
const signer = wallet.connect(provider);

// Function to send ETH
async function sendETH(toAddress, amount) {
  const transaction = {
    to: toAddress,
    value: ethers.utils.parseEther(amount.toString()),
  };

  const signedTransaction = await signer.signTransaction(transaction);
  const transactionHash = await signer.sendTransaction(signedTransaction);

  return transactionHash;
}

// Function to interact with smart contract
async function interactWithSmartContract(contractAddress, abi, functionName, ...args) {
  const contract = new ethers.Contract(contractAddress, abi, signer);
  const transaction = await contract[functionName](...args);

  return transaction;
}